import React, { useState } from 'react';

export default function RangeSlider({ min = 0, max = 100 }) {
  const [lo, setLo] = useState(20);
  const [hi, setHi] = useState(80);

  const onLo = (v) => setLo(Math.min(v, hi));
  const onHi = (v) => setHi(Math.max(v, lo));

  const pct = (v) => ((v - min) / (max - min)) * 100;

  const thumb = {
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    margin: 0,
    height: 24,
    background: 'none',
    pointerEvents: 'none',
    WebkitAppearance: 'none',
    appearance: 'none',
  };

  return (
    <div style={{ maxWidth: 320 }}>
      <div style={{ position: 'relative', height: 24 }}>
        <div style={{ position: 'absolute', top: 10, left: 0, right: 0, height: 4, background: '#e5e7eb', borderRadius: 2 }} />
        <div style={{ position: 'absolute', top: 10, height: 4, background: '#2563eb', borderRadius: 2, left: `${pct(lo)}%`, right: `${100 - pct(hi)}%` }} />
        <input
          type="range"
          min={min}
          max={max}
          value={lo}
          onChange={(e) => onLo(Number(e.target.value))}
          style={thumb}
          aria-label="Minimum"
        />
        <input
          type="range"
          min={min}
          max={max}
          value={hi}
          onChange={(e) => onHi(Number(e.target.value))}
          style={thumb}
          aria-label="Maximum"
        />
      </div>
      <output style={{ display: 'block', marginTop: 12, fontWeight: 600 }}>
        ${lo} – ${hi}
      </output>
      <style>{`
        input[type=range]::-webkit-slider-thumb { pointer-events: auto; -webkit-appearance: none; appearance: none; width: 18px; height: 18px; border-radius: 50%; background: #2563eb; border: 2px solid #fff; box-shadow: 0 1px 4px rgba(0,0,0,0.3); cursor: pointer; }
        input[type=range]::-moz-range-thumb { pointer-events: auto; width: 18px; height: 18px; border-radius: 50%; background: #2563eb; border: 2px solid #fff; cursor: pointer; }
      `}</style>
    </div>
  );
}

