import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-range-slider',
  template: `
    <div style="max-width: 320px;">
      <div style="position: relative; height: 24px;">
        <div style="position: absolute; top: 10px; left: 0; right: 0; height: 4px; background: #e5e7eb; border-radius: 2px;"></div>
        <div style="position: absolute; top: 10px; height: 4px; background: #2563eb; border-radius: 2px;" [style.left]="pct(lo) + '%'" [style.right]="(100 - pct(hi)) + '%'"></div>
        <input type="range" [min]="min" [max]="max" [value]="lo" aria-label="Minimum" (input)="onLo(toNum($any($event.target).value))" class="rng" />
        <input type="range" [min]="min" [max]="max" [value]="hi" aria-label="Maximum" (input)="onHi(toNum($any($event.target).value))" class="rng" />
      </div>
      <output style="display: block; margin-top: 12px; font-weight: 600;">${{ lo }} – ${{ hi }}</output>
    </div>
  `,
  styles: [`
    .rng { position: absolute; top: 0; left: 0; width: 100%; margin: 0; height: 24px; background: none; pointer-events: none; -webkit-appearance: none; appearance: none; }
    .rng::-webkit-slider-thumb { pointer-events: auto; -webkit-appearance: none; appearance: none; width: 18px; height: 18px; border-radius: 50%; background: #2563eb; border: 2px solid #fff; box-shadow: 0 1px 4px rgba(0,0,0,0.3); cursor: pointer; }
    .rng::-moz-range-thumb { pointer-events: auto; width: 18px; height: 18px; border-radius: 50%; background: #2563eb; border: 2px solid #fff; cursor: pointer; }
  `],
})
export class RangeSliderComponent {
  @Input() min = 0;
  @Input() max = 100;
  lo = 20;
  hi = 80;

  toNum(v: string): number {
    return Number(v);
  }

  onLo(v: number): void {
    this.lo = Math.min(v, this.hi);
  }

  onHi(v: number): void {
    this.hi = Math.max(v, this.lo);
  }

  pct(v: number): number {
    return ((v - this.min) / (this.max - this.min)) * 100;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Dual Range Slider Demo</h1>
      <app-range-slider [min]="0" [max]="100"></app-range-slider>
    </div>
  `,
})
export class AppComponent {}

@NgModule({
  declarations: [AppComponent, RangeSliderComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
